SELECT Country, COUNT(Singer_ID) AS number_of_singers
FROM singer
GROUP BY Country;

SELECT COUNT(Singer_ID) AS singer_count, Country
FROM singer
GROUP BY Country;

SELECT Fname, Age
FROM Student
WHERE EXISTS (SELECT 1 FROM Has_Pet WHERE Has_Pet.StuID = Student.StuID);

SELECT DISTINCT Fname, Age
FROM Student
JOIN Has_Pet ON Student.StuID = Has_Pet.StuID;

SELECT StuID, COUNT(PetID) AS pet_count
FROM Has_Pet
GROUP BY StuID;

SELECT cm.Maker, ml.Model
FROM car_makers cm
JOIN model_list ml ON cm.Id = ml.Maker;

SELECT car_makers.Maker, model_list.Model
FROM car_makers
JOIN model_list ON car_makers.Id = model_list.Maker;

SELECT countries.CountryName, countries.CountryId
FROM countries
JOIN car_makers ON countries.CountryId = car_makers.Country;

SELECT DISTINCT c.CountryName, c.CountryId
FROM countries c
JOIN car_makers cm ON c.CountryId = cm.Country;

SELECT COUNT(*) 
FROM cars_data 
WHERE Accelerate > (
    SELECT MAX(Accelerate) 
    FROM cars_data 
    WHERE Horsepower = (
        SELECT MAX(Horsepower) 
        FROM cars_data
    )
);

SELECT COUNT(*) 
FROM cars_data 
WHERE Accelerate > (
    SELECT Accelerate 
    FROM cars_data 
    WHERE CAST(Horsepower AS NUMERIC) = (
        SELECT MAX(CAST(Horsepower AS NUMERIC)) 
        FROM cars_data
    )
);

SELECT MAX(CAST(MPG AS numeric)) AS MaxMPG
FROM cars_data
WHERE Cylinders = 8 OR Year < 1980;

